public int active()
{
    int                 ret;
    ret = next active();

    element.design().controlName('BankAccountTable_ETGinstitutionCode').visible(ETGCanadaParameters::find().EnableProformInvoiceGenerate);
    element.design().controlName('BankAccountTable_ETGBrancTransit').visible(ETGCanadaParameters::find().EnableProformInvoiceGenerate);

    return ret;
}
